import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

bp = extract(b)
ap = extract(a)
changes = []
for k in sorted(set(list(bp.keys()) + list(ap.keys()))):
    bv = bp.get(k, 'N/A')
    av = ap.get(k, 'N/A')
    if bv != av:
        changes.append((k, bv, av))

if changes:
    print('CHANGES:')
    for (proj, tfm, pkg), bv, av in changes:
        print(f'  {proj} ({tfm}): {pkg} {bv} -> {av}')
else:
    print('NO CHANGES - all versions match')
