import sys, json
data = json.load(sys.stdin)
with open('after-cpm-packages.json', 'w') as f:
    json.dump(data, f, indent=2)
print('Wrote after-cpm-packages.json')

# Also check the pre-existing baseline
with open('baseline-packages.json') as f:
    content = f.read()
# Try to find valid JSON start
idx = content.find('{')
if idx > 0:
    content = content[idx:]
baseline = json.loads(content)

def extract(d):
    pkgs = {}
    for proj in d.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

bp = extract(baseline)
ap = extract(data)
changes = []
for k in sorted(set(list(bp.keys()) + list(ap.keys()))):
